static const char kWifiConfigPortalNetworkSectionTemplate[] = "<section class=\"panel\">\n  <div class=\"section-head\">\n    <h2 data-i18n=\"network\">Network</h2>\n    <span class=\"hint\" id=\"scan-status\" data-i18n=\"scanIdle\">Click Scan to find nearby WiFi networks.</span>\n  </div>\n  <div class=\"grid\">\n    <form class=\"item-form span-2\" method=\"post\" action=\"/save_wifi\">\n      <div class=\"subgrid\">\n        <div>\n          <label data-i18n=\"wifiSsid\">WiFi SSID</label>\n          <div class=\"row\">\n            <select id=\"wifi-ssid-select\" name=\"wifi_ssid\">\n              <option value=\"\" data-i18n=\"selectWifi\">Select detected WiFi...</option>\n              {{WIFI_OPTIONS}}\n            </select>\n            <button class=\"secondary btn-small icon-btn\" type=\"button\" onclick=\"scanWifi()\" data-i18n-title=\"scan\" title=\"Scan\" aria-label=\"Scan\">&#x21BB;</button>\n          </div>\n        </div>\n        <div><label data-i18n=\"wifiPassword\">WiFi Password</label><input name=\"wifi_password\" value=\"{{WIFI_PASSWORD}}\"></div>\n      </div>\n      <div class=\"actions\"><button class=\"btn-small\" type=\"submit\" data-i18n=\"saveItem\">Save</button></div>\n    </form>\n    <form class=\"item-form span-2\" method=\"post\" action=\"/save_wifi\">\n      <div class=\"subgrid\">\n        <div><label>DHCP</label><input type=\"hidden\" name=\"wifi_dhcp_present\" value=\"1\"><label class=\"hint\"><input id=\"wifi-dhcp-enabled\" type=\"checkbox\" name=\"wifi_dhcp_enabled\" value=\"1\" onchange=\"syncDhcpFields()\" {{DHCP_CHECKED}}><span>Use DHCP for station IP</span></label></div>\n        <div><label>WiFi IP</label><input class=\"wifi-static-field\" name=\"wifi_ip\" value=\"{{WIFI_IP}}\"></div>\n        <div><label>WiFi Mask</label><input class=\"wifi-static-field\" name=\"wifi_mask\" value=\"{{WIFI_MASK}}\"></div>\n        <div><label>WiFi Gateway</label><input class=\"wifi-static-field\" name=\"wifi_gateway\" value=\"{{WIFI_GATEWAY}}\"></div>\n        <div><label>WiFi DNS</label><input class=\"wifi-static-field\" name=\"wifi_dns\" value=\"{{WIFI_DNS}}\"></div>\n      </div>\n      <div class=\"actions\"><button class=\"btn-small\" type=\"submit\" data-i18n=\"saveItem\">Save</button></div>\n    </form>\n  </div>\n</section>";
static const char kWifiConfigPortalDeviceSectionsTemplate[] = "<section class=\"panel\">\n  <div class=\"section-head\"><h2 data-i18n=\"server\">Server</h2></div>\n  <div class=\"grid\">\n    <form class=\"item-form span-2\" method=\"post\" action=\"/save_nrl\">\n      <div class=\"subgrid\">\n        <div><label data-i18n=\"serverHost\">Server Host / IP</label><input name=\"server_host\" value=\"{{SERVER_HOST}}\"></div>\n        <div><label data-i18n=\"serverPort\">Server Port</label><input name=\"server_port\" value=\"{{SERVER_PORT}}\"></div>\n      </div>\n      <div class=\"actions\"><button class=\"btn-small\" type=\"submit\" data-i18n=\"saveItem\">Save</button></div>\n    </form>\n  </div>\n</section>\n<section class=\"panel\">\n  <div class=\"section-head\"><h2 data-i18n=\"radio\">Radio</h2></div>\n  <div class=\"grid\">\n    <form class=\"item-form span-2\" method=\"post\" action=\"/save_nrl\">\n      <div class=\"subgrid\">\n        <div class=\"span-2\"><label data-i18n=\"channel\">Channel (0-7)</label><input name=\"channel\" value=\"{{CHANNEL}}\"></div>\n        <div><label data-i18n=\"callsign\">Callsign</label><input name=\"callsign\" value=\"{{CALLSIGN}}\"></div>\n        <div><label data-i18n=\"callsignSsid\">Callsign SSID</label><input name=\"callsign_ssid\" value=\"{{CALLSIGN_SSID}}\"></div>\n      </div>\n      <div class=\"actions\"><button class=\"btn-small\" type=\"submit\" data-i18n=\"saveItem\">Save</button></div>\n    </form>\n  </div>\n</section>";
